@Composable fun GuideMenuScreen( sections: List<GuideSection>, onBack: () -> Unit, onSectionClick: (Int) -> Unit, modifier: Modifier = Modifier ) { Scaffold( modifier = modifier.fillMaxSize(), topBar = { ScreenHeader( title = stringResource(id = R.string.survival_guide_title), onBack = onBack ) } ) { innerPadding -> Column( modifier = Modifier .fillMaxSize() .padding(innerPadding) .padding(16.dp) .verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(12.dp) ) { Text(text = stringResource(id = R.string.survival_guide_menu_hint)) sections.forEachIndexed { index, section -> Button( onClick = { onSectionClick(index) }, modifier = Modifier.fillMaxWidth() ) { Text( text = stringResource(id = section.titleRes), textAlign = TextAlign.Start, modifier = Modifier.fillMaxWidth() ) } } } } }

